module top_module(
  input clk,
  input reset_n,
  output [3:0] count
);reg [3:0] decrementer = 4'd0;

  always @(posedge clk, negedge reset_n) begin
    if (!reset_n) begin
      decrementer <= 4'd0;
    end else if (decrementer == 4'd9) begin
      decrementer <= 4'd0;
    end else begin
      decrementer <= decrementer + 1;
    end
  end

  assign count = decrementer;

endmodule
